package com.example.userapp.network;

import com.example.userapp.BuildConfig;

import java.util.concurrent.TimeUnit;

import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class ApiClient {

    private static final int CONNECT_TIMEOUT_SECONDS = 30;
    private static final int READ_TIMEOUT_SECONDS = 30;
    private static final int WRITE_TIMEOUT_SECONDS = 30;

    private static volatile ApiClient instance;
    private final Retrofit retrofit;
    private final UserApiService userApiService;

    private ApiClient(AuthInterceptor.TokenProvider tokenProvider) {
        OkHttpClient okHttpClient = buildOkHttpClient(tokenProvider);
        retrofit = buildRetrofit(okHttpClient);
        userApiService = retrofit.create(UserApiService.class);
    }

    public static ApiClient getInstance() {
        return getInstance(null);
    }

    public static ApiClient getInstance(AuthInterceptor.TokenProvider tokenProvider) {
        if (instance == null) {
            synchronized (ApiClient.class) {
                if (instance == null) {
                    instance = new ApiClient(tokenProvider);
                }
            }
        }
        return instance;
    }

    public static void resetInstance() {
        synchronized (ApiClient.class) {
            instance = null;
        }
    }

    private OkHttpClient buildOkHttpClient(AuthInterceptor.TokenProvider tokenProvider) {
        OkHttpClient.Builder builder = new OkHttpClient.Builder()
                .connectTimeout(CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .readTimeout(READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .writeTimeout(WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS);

        if (tokenProvider != null) {
            builder.addInterceptor(new AuthInterceptor(tokenProvider));
        }

        if (BuildConfig.ENABLE_LOGGING) {
            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor();
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BODY);
            builder.addInterceptor(loggingInterceptor);
        }

        return builder.build();
    }

    private Retrofit buildRetrofit(OkHttpClient okHttpClient) {
        return new Retrofit.Builder()
                .baseUrl(BuildConfig.BASE_URL)
                .client(okHttpClient)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
    }

    public UserApiService getUserApiService() {
        return userApiService;
    }

    public Retrofit getRetrofit() {
        return retrofit;
    }
}

