package com.example.userapp.viewmodel;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MediatorLiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import com.example.userapp.model.User;
import com.example.userapp.repository.Resource;
import com.example.userapp.repository.UserRepository;

import java.util.List;

public class UserViewModel extends ViewModel {

    private final UserRepository userRepository;
    private final MediatorLiveData<Resource<List<User>>> usersLiveData = new MediatorLiveData<>();
    private final MediatorLiveData<Resource<User>> selectedUserLiveData = new MediatorLiveData<>();
    private LiveData<Resource<List<User>>> currentUsersSource;
    private LiveData<Resource<User>> currentUserSource;

    public UserViewModel() {
        this.userRepository = new UserRepository();
    }

    public UserViewModel(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    public LiveData<Resource<List<User>>> getUsersLiveData() {
        return usersLiveData;
    }

    public LiveData<Resource<User>> getSelectedUserLiveData() {
        return selectedUserLiveData;
    }

    public void fetchUsers() {
        if (currentUsersSource != null) {
            usersLiveData.removeSource(currentUsersSource);
        }
        currentUsersSource = userRepository.getUsers();
        usersLiveData.addSource(currentUsersSource, resource -> {
            usersLiveData.setValue(resource);
        });
    }

    public void fetchUsers(int page, int limit) {
        if (currentUsersSource != null) {
            usersLiveData.removeSource(currentUsersSource);
        }
        currentUsersSource = userRepository.getUsers(page, limit);
        usersLiveData.addSource(currentUsersSource, resource -> {
            usersLiveData.setValue(resource);
        });
    }

    public void fetchUserById(long userId) {
        if (currentUserSource != null) {
            selectedUserLiveData.removeSource(currentUserSource);
        }
        currentUserSource = userRepository.getUserById(userId);
        selectedUserLiveData.addSource(currentUserSource, resource -> {
            selectedUserLiveData.setValue(resource);
        });
    }
}

