package com.example.userapp;

import android.app.Application;
import android.util.Log;

import com.example.userapp.network.ApiClient;

public class UserApp extends Application {

    private static final String TAG = "UserApp";

    @Override
    public void onCreate() {
        super.onCreate();

        Log.d(TAG, "App started in environment: " + BuildConfig.ENV_NAME);
        Log.d(TAG, "Base URL: " + BuildConfig.BASE_URL);

        // Initialize the API client (optionally with a token provider)
        ApiClient.getInstance(() -> {
            // In a real app, retrieve the token from SharedPreferences or secure storage
            // For MVP, return null if no auth is needed yet
            return null;
        });
    }
}

